arguments.command:
cd /tmp/CompCert
ls -la ccomp
./ccomp --version
cat > /tmp/hello.c <<'EOF'
#include <stdio.h>
int fib(int n){ return n<2 ? n : fib(n-1)+fib(n-2); }
int main(void){ printf("hello compcert %d\n", fib(10)); return 0; }
EOF
./ccomp -o /tmp/hello /tmp/hello.c && /tmp/hello; echo "RUN_EXIT=$?"

